mapper.select:
SELECT *
FROM ${tableName}
WHERE create_time >= #{start}
AND create_time < #{end}

SELECT COUNT(*)
FROM ${tableName}
WHERE create_time >= #{start}
AND create_time < #{end}
AND server = 'CN'

SELECT *
FROM ${tableName}
WHERE stage_id = #{stageId}
AND server = 'CN'

SELECT *
FROM ${tableName}
WHERE create_time >= #{start}
AND create_time < #{end}
AND server = 'CN'

SELECT MIN(create_time) AS firstTime, MAX(create_time) AS lastTime, COUNT(*) AS cnt
FROM ${tableName}
WHERE create_time >= #{start}
AND create_time < #{end}
AND server = 'CN'

SELECT stage_id AS stageId, SUM(times) AS times
FROM ${tableName}
WHERE create_time >= #{start}
AND create_time < #{end}
AND server = 'CN'
GROUP BY stage_id
